function minTimeToRepair(ranks, cars) {
    ranks.sort((a, b) => a - b);
    let low = 0, high = 100 * cars * cars;
    while (low < high) {
        const mid = low + Math.floor((high - low) / 2);
        let total_cars_repaired = 0;
        for (const rank of ranks) {
            const cars_repaired = Math.min(cars, Math.floor(mid / (rank * rank)));
            total_cars_repaired += cars_repaired;
            if (total_cars_repaired >= cars) break;
        }
        if (total_cars_repaired >= cars) high = mid;
        else low = mid + 1;
    }
    return low;
}
```


    1. Sort mechanics by their ranks.
2. Perform binary search to find the minimum time required to repair all cars:
    a. Initialize the boundaries `low` and `high`.
    b. Calculate the middle value `mid`.
    c. For each mechanic, calculate the number of cars they can repair in `mid` minutes and sum it to `total_cars_repaired`.
    d. Check if `total_cars_repaired` is greater than or equal to the number of cars. If yes, update `high = mid`. Otherwise, update `low = mid + 1`.
3. The answer is in the `low` variable.

