import java.util.Arrays;

public int minTimeToRepair(int[] ranks, int cars) {
    Arrays.sort(ranks);
    int low = 0, high = 100 * cars * cars;
    while (low < high) {
        int mid = low + (high - low) / 2;
        int total_cars_repaired = 0;
        for (int rank : ranks) {
            int cars_repaired = Math.min(cars, mid / (rank * rank));
            total_cars_repaired += cars_repaired;
            if (total_cars_repaired >= cars) break;
        }
        if (total_cars_repaired >= cars) high = mid;
        else low = mid + 1;
    }
    return low;
}
```


